    {
        "host", "connection", "keep-alive", "transfer-encoding",
        "te", "trailer", "upgrade", "proxy-authorization",
        "proxy-authenticate", "cookie", "set-cookie",
        "authorization"
    };
    return !blockedHeaders.Contains(headerName);
}

